// Тілге сай өнім деректерін алу
function getProdTr(p) {
  if (typeof currentLang === 'undefined' || currentLang === 'kk') return p;
  const tr = PROD_TR[p.n];
  if (!tr || !tr[currentLang]) return p;
  const t = tr[currentLang];
  const newTech = (p.tech && t.tech) ? {
    coverage: t.tech.coverage || p.tech.coverage,
    drying: t.tech.drying || p.tech.drying,
    temp: t.tech.temp || p.tech.temp,
    method: t.tech.method || p.tech.method,
    dilute: t.tech.dilute || p.tech.dilute,
    storage: t.tech.storage || p.tech.storage
  } : p.tech;
  return {
    ...p,
    n: t.n || p.n,
    desc: t.desc || p.desc,
    cat: (CAT_TR[currentLang] && CAT_TR[currentLang][p.cat]) || p.cat,
    pictos: t.pictos ? p.pictos.map((pc,i) => ({i:pc.i, v:(t.pictos[i]&&t.pictos[i].v)||pc.v, l:(t.pictos[i]&&t.pictos[i].l)||pc.l})) : p.pictos,
    usp: t.usp || p.usp,
    steps: t.steps || p.steps,
    tech: newTech
  };
}

// БЕТТЕР
function goPage(page, filterCat) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('nav a').forEach(a => a.classList.remove('active'));
  const pg = document.getElementById('page-' + page);
  if (pg) pg.classList.add('active');
  const nv = document.getElementById('nav-' + page);
  if (nv) nv.classList.add('active');
  window.scrollTo(0,0);
  if (page === 'products') {
    curCat = filterCat || '';
    renderProds();
    if (filterCat) {
      document.querySelectorAll('.ccat').forEach(el => {
        el.classList.remove('active');
        if (el.textContent.trim().startsWith(filterCat)) el.classList.add('active');
      });
    }
  }
}

function filterAndGo(cat) { goPage('products', cat); }

// ӨНІМДЕР
let curCat = '';
let srchQ = '';

function renderProds() {
  const list = PRODUCTS.filter(p =>
    (!curCat || p.cat === curCat) &&
    (!srchQ || p.n.toLowerCase().includes(srchQ.toLowerCase()))
  );
  const cnt = document.getElementById('prod-count');
  const pu = (typeof currentLang !== 'undefined' && typeof TRANSLATIONS !== 'undefined') ? (TRANSLATIONS[currentLang].prod_unit || 'өнім') : 'өнім';
  if (cnt) cnt.textContent = list.length + ' ' + pu;
  const el = document.getElementById('all-prods');
  if (el) el.innerHTML = list.map(p => prodCard(p)).join('');
}

function renderHomeProds() {
  const el = document.getElementById('home-prods');
  if (!el) return;
  el.innerHTML = PRODUCTS.slice(0,4).map(p => prodCard(p)).join('');
}

function prodCard(p) {
  const tp = getProdTr(p);
  const img = PH[p.n];
  const imgHtml = img
    ? `<img src="${img}" alt="${tp.n}" class="prod-img" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
    : '';
  return `<div class="prod-card" onclick="openModal('${p.n.replace(/'/g, "\\'")}')">
    ${imgHtml}
    <div class="prod-img-ph" style="${img?'display:none':''}">🎨</div>
    <div class="prod-body">
      <div class="prod-cat">${tp.cat}</div>
      <div class="prod-name">${tp.n}</div>
    </div>
  </div>`;
}

function openModal(name) {
  const p = PRODUCTS.find(x => x.n === name);
  if (!p) return;
  const tp = getProdTr(p);
  const TL = (typeof currentLang !== 'undefined' && typeof TRANSLATIONS !== 'undefined') ? TRANSLATIONS[currentLang] : {};
  const btnOrder = TL.btn_order || 'Тапсырыс';
  const inStock  = TL.in_stock  || '✓ Бар';
  const outStock = TL.out_stock || 'Жоқ';
  const modalSize = TL.modal_size || 'Қаптама өлшемі';
  const modalUsp = TL.modal_usp || 'Артықшылықтары';
  const modalTech = TL.modal_tech || 'Техникалық деректер';
  const modalSteps = TL.modal_steps || 'Қолдану жолы';
  const unitTxt = TL.unit || 'дана';
  const bcProducts = TL.bc_products || 'Өнімдер';
  const img = PH[p.n] || '';

  // Breadcrumb
  const bcCat = document.getElementById('pd-bc-cat');
  const bcName = document.getElementById('pd-bc-name');
  const bcProd = document.querySelector('.bc-pd-products');
  if (bcCat) bcCat.textContent = tp.cat;
  if (bcName) bcName.textContent = tp.n;
  if (bcProd) bcProd.textContent = bcProducts;

  // Pictos
  const pictos = (tp.pictos||[]).map(pc => `
    <div class="pd-picto">
      <div class="pd-picto-icon">${pc.i}</div>
      <div class="pd-picto-val">${pc.v}</div>
      <div class="pd-picto-lbl">${pc.l}</div>
    </div>`).join('');

  // Badges
  const badges = (p.badges||[]).map(b => `<span class="pd-badge">${b}</span>`).join('');

  // Sizes
  const sizes = (p.fas||[]).map((f,i) =>
    `<button class="pd-size${i===0?' active':''}">${f} кг</button>`
  ).join('');

  // USP accordion
  const uspHtml = (tp.usp||[]).length ? `
    <div class="pd-acc">
      <div class="pd-acc-head open" onclick="pdToggle(this)">
        <span>${modalUsp}</span>
        <span class="pd-acc-arrow">▼</span>
      </div>
      <div class="pd-acc-body open">
        <ul class="pd-usp-list">
          ${(tp.usp||[]).map(u => `<li class="pd-usp-item"><span class="pd-usp-check">✓</span>${u}</li>`).join('')}
        </ul>
      </div>
    </div>` : '';

  // Tech accordion
  const techRows = tp.tech ? `
    <tr><td>${TL.tech_coverage||'Шығын'}</td><td>${tp.tech.coverage||'—'}</td></tr>
    <tr><td>${TL.tech_drying||'Кебу уақыты'}</td><td>${tp.tech.drying||'—'}</td></tr>
    <tr><td>${TL.tech_temp||'Жұмыс температурасы'}</td><td>${tp.tech.temp||'—'}</td></tr>
    ${tp.tech.method ? `<tr><td>${TL.tech_method||'Жағу тәсілі'}</td><td>${tp.tech.method}</td></tr>` : ''}
    ${tp.tech.dilute ? `<tr><td>${TL.tech_dilute||'Сұйылту'}</td><td>${tp.tech.dilute}</td></tr>` : ''}
    ${tp.tech.storage ? `<tr><td>${TL.tech_storage||'Сақтау'}</td><td>${tp.tech.storage}</td></tr>` : ''}
  ` : '';
  const techHtml = techRows ? `
    <div class="pd-acc">
      <div class="pd-acc-head" onclick="pdToggle(this)">
        <span>${modalTech}</span>
        <span class="pd-acc-arrow">▼</span>
      </div>
      <div class="pd-acc-body">
        <table class="pd-tech-table"><tbody>${techRows}</tbody></table>
      </div>
    </div>` : '';

  // Steps accordion
  const steps = (tp.steps||[]).map((s,i) => `
    <div class="pd-step">
      <div class="pd-step-n">${i+1}</div>
      <div>
        <div class="pd-step-t">${s[0]}</div>
        ${s[1] ? `<div class="pd-step-s">${s[1]}</div>` : ''}
      </div>
    </div>`).join('');
  const stepsHtml = steps ? `
    <div class="pd-acc">
      <div class="pd-acc-head" onclick="pdToggle(this)">
        <span>${modalSteps}</span>
        <span class="pd-acc-arrow">▼</span>
      </div>
      <div class="pd-acc-body">
        <div class="pd-steps">${steps}</div>
      </div>
    </div>` : '';

  // Render the full page
  document.getElementById('pd-content').innerHTML = `
    <div class="pd-wrap">
      <button class="pd-back" onclick="goPage('products')">← ${bcProducts}</button>
      <div class="pd-top">
        <div class="pd-img-wrap">
          ${img ? `<img src="${img}" alt="${tp.n}" class="pd-img">` : '<div class="pd-img-ph">🎨</div>'}
        </div>
        <div class="pd-info">
          <div class="pd-cat">${tp.cat}</div>
          <h1 class="pd-title">${tp.n}</h1>
          ${badges ? `<div class="pd-badges">${badges}</div>` : ''}
          <p class="pd-desc">${tp.desc}</p>
          ${pictos ? `<div class="pd-pictos">${pictos}</div>` : ''}
          ${sizes ? `
            <div class="pd-size-label">${modalSize}</div>
            <div class="pd-sizes">${sizes}</div>
          ` : ''}
          <button class="pd-order-btn" onclick="orderWA('${name.replace(/'/g,"\\'")}')">
            💬 ${btnOrder}
          </button>
          <div class="pd-stock">
            ${p.qty > 0 ? inStock : outStock} — ${p.qty} ${unitTxt}
          </div>
        </div>
      </div>
    </div>
    <div class="pd-accordions">
      ${uspHtml}
      ${techHtml}
      ${stepsHtml}
    </div>
  `;

  // Navigate to the product-detail page
  goPage('product-detail');

  // Highlight products nav
  const nv = document.getElementById('nav-products');
  if (nv) nv.classList.add('active');
}

function pdToggle(head) {
  const body = head.nextElementSibling;
  const isOpen = body.classList.contains('open');
  body.classList.toggle('open');
  head.classList.toggle('open');
}

function closeModal() {
  // Legacy — no longer used, kept for compatibility
  goPage('products');
}

function openDetail(name) {
  openModal(name);
}

function orderWA(name) {
  const msgs = {kk:'Сәлем! "'+name+'" өнімін тапсырыс бергім келеді.', ru:'Здравствуйте! Хочу заказать "'+name+'".', en:'Hello! I would like to order "'+name+'".'};
  const lang = (typeof currentLang !== 'undefined') ? currentLang : 'kk';
  const msg = encodeURIComponent(msgs[lang] || msgs.kk);
  window.open('https://wa.me/77770050757?text=' + msg, '_blank');
}

function clrCat(cat, el) {
  curCat = cat;
  document.querySelectorAll('.ccat').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
  renderProds();
}

function clrSrch(q) { srchQ = q; renderProds(); }

function setLang(lang) {
  document.querySelectorAll('.lang-btn').forEach(b => b.classList.remove('active'));
  const lb = document.getElementById('lang-' + lang);
  if (lb) lb.classList.add('active');
}

window.onload = () => { renderHomeProds(); renderProds(); if(typeof renderCats==="function") renderCats(); };

// Санат карточкаларын render
function renderCats() {
  const T = (typeof currentLang !== 'undefined' && typeof TRANSLATIONS !== 'undefined') ? TRANSLATIONS[currentLang] : null;
  const grid = document.getElementById('cat-grid');
  if (!grid) return;
  const cats = T ? T.cats : [
    {key:'Фасадтық бояу', img:'images/cat_fasad.webp',    name:'Фасадтық бояу', cnt:'2 өнім'},
    {key:'Ішкі бояу',     img:'images/cat_interior.webp', name:'Ішкі бояу',     cnt:'5 өнім'},
    {key:'Антимороз',     img:'images/cat_antimoros.webp',name:'Антимороз',     cnt:'1 өнім'},
    {key:'Гидроизоляция', img:'images/cat_hydro.webp',    name:'Гидроизоляция', cnt:'1 өнім'},
    {key:'Грунтовка',     img:'images/cat_grunt.webp',    name:'Грунтовка',     cnt:'2 өнім'},
    {key:'Декоративті',   img:'images/cat_dekor.webp',    name:'Декоративті',   cnt:'4 өнім'},
    {key:'Бетон-контакт', img:'images/Betonkontakt_Optimized.webp', name:'Бетон-контакт', cnt:'1 өнім'},
  ];
  grid.innerHTML = cats.map(c => `
    <div class="cat-card" onclick="filterAndGo('${c.key}')">
      <div class="cat-img-wrap">
        <img class="cat-img" src="${c.img}" alt="${c.name}" onerror="this.parentElement.style.background='#f0f0f0'">
      </div>
      <div class="cat-body">
        <div class="cat-name">${c.name}</div>
        <div class="cat-cnt">${c.cnt}</div>
      </div>
      <div class="cat-arrow">→</div>
    </div>`).join('');
}
